"use strict";(globalThis.webpackChunkblog_page=globalThis.webpackChunkblog_page||[]).push([[801],{1355(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>a,toc:()=>l});var a=n(8885),i=n(2615),s=n(7545);const o={slug:"DisappearingInquiry",title:"Disappearing Inquiry",authors:["prakash-hegade"]},r=void 0,h={authorsImageUrls:[void 0]},l=[];function d(e){const t={p:"p",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"Are we forgetting how to be curious? I mean, if there isn\u2019t a puzzle anymore, there should not be any curiosity anymore as well. Not knowing answers was not considered as a defect in the human system. It was a hook that made thinking possible. Dewey\u2019s greatest concern, in his book \u2018How we Think\u2019 wasn't the acquisition of facts; rather, it was about the cultivation of habits of thinking. He believed education was the process of training the mind to sit with uncertainty and to test claims against evidence. I will ask again, are we forgetting how to stay curious?"}),"\n",(0,i.jsx)(t.p,{children:"Inductive thinking starts from small observations and moves toward a bigger understanding. We notice patterns from experiences and slowly form an idea or conclusion. Deductive thinking works the other way around. It begins with an idea or rule and applies it to specific situations to see if it makes sense. Good thinking happens when both work together, back and forth. Real understanding develops when people continuously move between experience and reasoning, testing ideas, questioning conclusions, and refining their thoughts through reflection and experience. I mean a mix of induction and deduction."}),"\n",(0,i.jsx)(t.p,{children:"Imagine, what if the doctor always consulted a diagnostic system before observing the patient? What if the carpenter always searched for the next step before understanding the wood in front of him? What if the teacher always waited to see what experts had already said before responding to a student? Would their skill deepen with experience? Or would they eventually become dependent on an external intelligence? What does it mean to be a doctor, carpenter or a teacher? Would these crafts still stay distinct, or would they all slowly become the same act of looking elsewhere for answers?"}),"\n",(0,i.jsx)(t.p,{children:"The easiest thing for the mind is to accept the first reasonable answer it sees. Real thinking probably begins only when we resist that urge and stay with uncertainty a little longer. What if, instead we started reflecting more? There is a difference between using AI to think and using AI instead of thinking. Ironically, as machines become more intelligent, human reflection may become even more valuable. Thinking is not something humans naturally do well. It is something we slowly learn through practice, experience, mistakes, and repeated encounters with problems that matter to us. Somewhere between not knowing and knowing, the mind is forced to work, and that space matters the most. The deepest habits of thinking are built when something matters enough that we struggle with it, stay with it, and try to figure it out ourselves. What do you think happens to the human mind when we remove the very friction that once made thinking possible?"}),"\n",(0,i.jsx)(t.p,{children:"A doctor who has seen thousands of patients develops a certain kind of attention. A carpenter's hands know things before his mind articulates them. A teacher who has sat with struggling students learns to read confusion in the room. These aren't formal skills written in a manual. They are habits built through lived experience and reflection on that experience."})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},7545(e,t,n){n.d(t,{R:()=>o,x:()=>r});var a=n(9471);const i={},s=a.createContext(i);function o(e){const t=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),a.createElement(s.Provider,{value:t},e.children)}},8885(e){e.exports=JSON.parse('{"permalink":"/vled/DisappearingInquiry","editUrl":"https://github.com/vicharanashala/vled/tree/master/blog-page/blog/2026-05-10-DisappearingInquiry/index.md","source":"@site/blog/2026-05-10-DisappearingInquiry/index.md","title":"Disappearing Inquiry","description":"Are we forgetting how to be curious? I mean, if there isn\u2019t a puzzle anymore, there should not be any curiosity anymore as well. Not knowing answers was not considered as a defect in the human system. It was a hook that made thinking possible. Dewey\u2019s greatest concern, in his book \u2018How we Think\u2019 wasn\'t the acquisition of facts; rather, it was about the cultivation of habits of thinking. He believed education was the process of training the mind to sit with uncertainty and to test claims against evidence. I will ask again, are we forgetting how to stay curious?","date":"2026-05-10T00:00:00.000Z","tags":[],"readingTime":2.54,"hasTruncateMarker":true,"authors":[{"name":"Prakash Hegade","title":"Instructional Systems Scientist","url":"https://linkedin.com/in/prakash-hegade-16879917","page":{"permalink":"/vled/authors/all-prakash-hegade-articles"},"socials":{"linkedin":"https://www.linkedin.com/in/prakash-hegade-16879917/"},"imageURL":"https://github.com/prakashbh.png","key":"prakash-hegade"}],"frontMatter":{"slug":"DisappearingInquiry","title":"Disappearing Inquiry","authors":["prakash-hegade"]},"unlisted":false,"prevItem":{"title":"Invisible Layers","permalink":"/vled/InvisibleLayers"},"nextItem":{"title":"Beyond Easy Answers","permalink":"/vled/BeyondEasyAnswers"}}')}}]);